SELECT 
FROM sys_defense_log


        AND event_id = #{eventId}


        AND defense_type = #{defenseType}


        AND defense_target LIKE CONCAT('%', #{defenseTarget}, '%')


        AND execute_status = #{executeStatus}


        AND execute_time >= #{startTime}


        AND execute_time <= #{endTime}


ORDER BY execute_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM sys_defense_log


        AND event_id = #{eventId}


        AND defense_type = #{defenseType}


        AND defense_target LIKE CONCAT('%', #{defenseTarget}, '%')


        AND execute_status = #{executeStatus}


        AND execute_time >= #{startTime}


